// The proof obligation here is unprovable from the given postconditions.
    //
    // DelegationMap has fields:
    //     lows: StrictlyOrderedMap<K>   (concrete, contains Vec internals)
    //     m:    Ghost<Map<K, AbstractEndPoint>>
    //
    // Both `view(self)` and `valid(self)` on DelegationMap are declared
    //     #[verifier::external_body]  pub closed spec fn ...
    // i.e. completely uninterpreted spec functions. From
    //     r1.valid()  &&  r2.valid()
    //     r1@ == Map::total(|k:K| id_zero@)  &&  r2@ == Map::total(|k:K| id_zero@)
    // we can derive that view(r1)==view(r2) (trivially), but view() is not
    // injective: nothing relates the two opaque calls back to the struct
    // fields `lows` and `m`. Two distinct DelegationMap values can therefore
    // share the same view and same validity, so r1 == r2 is not derivable
    // without an axiom we are forbidden from introducing.
    //
    // Below we still propagate the strongest honest consequence in case the
    // SMT solver can use it; the final structural equality is what fails.
    if r1.valid() && r1@ == Map::total(|k: K| id_zero@)
        && r2.valid() && r2@ == Map::total(|k: K| id_zero@) {
        assert(r1@ =~= r2@);
        assert(r1@ == r2@);
    }
